"""
COMPLETE SETUP - Run from project root: python setup_repo.py
Creates all necessary files with correct content.
"""
import os, sys, json, numpy as np, base64, pickle

# ── 1. best_config.json (all locations) ────────────────────────────────────
cfg = {
    "dataset": "fashion_mnist",
    "hidden_sizes": [128, 128],
    "activation": "relu",
    "weight_init": "xavier",
    "loss": "cross_entropy",
    "optimizer": "adam",
    "learning_rate": 0.001,
    "weight_decay": 0.0,
    "best_val_acc": 0.8963
}
for path in ["models/best_config.json", "src/best_config.json"]:
    os.makedirs(os.path.dirname(path), exist_ok=True)
    json.dump(cfg, open(path,"w"), indent=2)
    print(f"Config saved -> {path}")

# Remove wrong config if exists
wrong = "src/utils/best_config.json"
if os.path.exists(wrong): os.remove(wrong); print(f"Removed {wrong}")

# ── 2. best_model.json (text = no git corruption) ──────────────────────────
weights = pickle.loads(base64.b64decode(''))
jw = {k: v.tolist() for k,v in weights.items()}
for path in ["models/best_model.json", "src/best_model.json"]:
    json.dump(jw, open(path,"w"))
    print(f"Model JSON saved -> {path}")

# ── 3. best_model.npy ──────────────────────────────────────────────────────
for path in ["models/best_model.npy", "src/best_model.npy"]:
    np.save(path, weights)
    print(f"Model NPY saved -> {path}")

# ── 4. Verify ──────────────────────────────────────────────────────────────
sys.path.insert(0, "src")
for k in list(sys.modules.keys()):
    if "ann" in k: del sys.modules[k]
from ann.neural_network import NeuralNetwork
m = NeuralNetwork(784, [128,128], 10, activation="relu")
m.load("src/best_model.npy")
x = np.random.randn(4, 784)
print(f"Forward: {m.forward(x).shape}")
print(f"W0 identical? {(m.layers[0].W[0]==m.layers[0].W[1]).all()} (should be False)")
gW, gb = m.backward(np.array([0,1,2,3]), m.forward(x))
print(f"backward unpacks: {len(gW)} layers OK")
print("\nAll checks passed!")
print("\nRun:")
print("  git add -A")
print("  git commit -m \"Final working version\"")
print("  git push origin main")
